/****** Object:  View [dbo].[vw_AssetsExportList]    Script Date: 20/07/2026 9:29:42 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[vw_AssetsExportList]
AS
SELECT AT.Assets.AssetID, AT.Assets.CompanyID, GSET.Companies.CompanyName, AT.Assets.AssetCode, AT.Assets.AssetImage, AT.Assets.AssetDesc, AT.Assets.LocationID, ATSET.LocationTypes.Location, AT.Assets.LocDetailID, 
                  ATSET.LocationDetails.Floor, ATSET.LocationDetails.Zone, ATSET.LocationDetails.Room, AT.Assets.GroupID, ATSET.GroupTypes.GroupName, AT.Assets.CategoryID, ATSET.CategoryTypes.Category, AT.Assets.Donation, 
                  AT.Assets.ContactID, GTBL.Contacts.ContactName, AT.Assets.PurchaseOrderNo, AT.Assets.PurchaseDate, AT.Assets.PurchasePrice, AT.Assets.PurchaseCurCode, AT.Assets.InServiceDate, AT.Assets.InvoiceNo, AT.Assets.InvoiceDate, 
                  AT.Assets.AccountingEntryDate, AT.Assets.AccountingEntryJVNo, AT.Assets.BarcodeNumber, AT.Assets.SerialNumber, AT.Assets.BrandID, ATSET.BrandTypes.BrandDesc, AT.Assets.Model, AT.Assets.StatusID, 
                  ATSET.StatusTypes.Status, AT.Assets.StatusDate, AT.Assets.Remark, AT.Assets.InstalledAt, AT.Assets.OwnerID, ATSET.OwnerTypes.OwnerDesc, AT.Assets.OwnerInfo, AT.Assets.HREmpIDUsedBy
FROM     AT.Assets INNER JOIN
                  ATSET.OwnerTypes ON AT.Assets.OwnerID = ATSET.OwnerTypes.OwnerID AND AT.Assets.OwnerID = ATSET.OwnerTypes.OwnerID AND AT.Assets.OwnerID = ATSET.OwnerTypes.OwnerID AND 
                  AT.Assets.OwnerID = ATSET.OwnerTypes.OwnerID AND AT.Assets.OwnerID = ATSET.OwnerTypes.OwnerID LEFT OUTER JOIN
                  ATSET.StatusTypes ON AT.Assets.StatusID = ATSET.StatusTypes.StatusID AND AT.Assets.StatusID = ATSET.StatusTypes.StatusID LEFT OUTER JOIN
                  ATSET.BrandTypes ON AT.Assets.BrandID = ATSET.BrandTypes.BrandID AND AT.Assets.BrandID = ATSET.BrandTypes.BrandID AND AT.Assets.BrandID = ATSET.BrandTypes.BrandID AND 
                  AT.Assets.BrandID = ATSET.BrandTypes.BrandID AND AT.Assets.BrandID = ATSET.BrandTypes.BrandID LEFT OUTER JOIN
                  GSET.Currencies ON AT.Assets.PurchaseCurCode = GSET.Currencies.CurCode AND AT.Assets.PurchaseCurCode = GSET.Currencies.CurCode AND AT.Assets.PurchaseCurCode = GSET.Currencies.CurCode LEFT OUTER JOIN
                  GTBL.Contacts ON AT.Assets.ContactID = GTBL.Contacts.ContactID AND AT.Assets.ContactID = GTBL.Contacts.ContactID AND AT.Assets.ContactID = GTBL.Contacts.ContactID AND AT.Assets.ContactID = GTBL.Contacts.ContactID AND 
                  AT.Assets.ContactID = GTBL.Contacts.ContactID LEFT OUTER JOIN
                  ATSET.LocationDetails ON AT.Assets.LocDetailID = ATSET.LocationDetails.LocDetailID AND AT.Assets.LocDetailID = ATSET.LocationDetails.LocDetailID LEFT OUTER JOIN
                  ATSET.LocationTypes ON AT.Assets.LocationID = ATSET.LocationTypes.LocationID AND AT.Assets.LocationID = ATSET.LocationTypes.LocationID LEFT OUTER JOIN
                  ATSET.CategoryTypes ON AT.Assets.CategoryID = ATSET.CategoryTypes.CategoryID AND AT.Assets.CategoryID = ATSET.CategoryTypes.CategoryID AND AT.Assets.CategoryID = ATSET.CategoryTypes.CategoryID AND 
                  AT.Assets.CategoryID = ATSET.CategoryTypes.CategoryID AND AT.Assets.CategoryID = ATSET.CategoryTypes.CategoryID LEFT OUTER JOIN
                  ATSET.GroupTypes ON AT.Assets.GroupID = ATSET.GroupTypes.GroupID LEFT OUTER JOIN
                  GSET.Companies ON AT.Assets.CompanyID = GSET.Companies.CompanyID
GO
