	SELECT  AT.Depreciations.DepID, AT.Depreciations.DepreciationDate, AT.Depreciations.Remark, AT.Depreciations.CreatedByFullName, AT.Depreciations.CreatedByDateTime, AT.Assets.AssetCode, AT.Assets.AssetDesc, 
