    @AssetID int,
    @AttID int,
    @FromDate date,
    @ToDate date,
    @SupplierContactID int,
    @Cost float,
    @CurCode char(3),
    @Remark nvarchar(100),
    @Original_MaintID int,
    @Original_AssetID int,
    @IsNull_AttID Int,
    @Original_AttID int,
    @Original_FromDate date,
    @Original_ToDate date,
    @Original_SupplierContactID int,
