    WHERE ([MaintID] = @Original_MaintID)
      AND ([AssetID] = @Original_AssetID)
      AND ((@IsNull_AttID = 1 AND [AttID] IS NULL) OR ([AttID] = @Original_AttID))
      AND ([FromDate] = @Original_FromDate)
