CREATE PROCEDURE [NOTIF].[stpGetNotifications]
(
    @UserID smallint
)
AS
    SET NOCOUNT ON;
    SELECT TOP 50
        NotifID, UserID, CompanyID, Type, EntityID, AssetID, Message, IsRead, CreatedAt
    FROM  NOTIF.Notifications
    WHERE UserID = @UserID
    ORDER BY CreatedAt DESC;
