CREATE   PROCEDURE [SEC].[stpUsersI]
(
    @UserName      NVARCHAR(100),
    @Password      NVARCHAR(256),
    @FullName      NVARCHAR(100),
    @EmailAddress  NVARCHAR(255),
    @RoleID        TINYINT
)
AS
BEGIN
    SET NOCOUNT OFF;

    INSERT INTO SEC.Users (UserName, UserPassword, FullName, EmailAddress, RoleID)
    VALUES (@UserName, HASHBYTES('SHA2_256', @Password), @FullName, @EmailAddress, @RoleID);

    SELECT SCOPE_IDENTITY() AS UserID;
END
GO
/****** Object:  StoredProcedure [SEC].[stpUsersS]    Script Date: 20/07/2026 9:29:42 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE   PROCEDURE [SEC].[stpUsersS]
AS
BEGIN
    SET NOCOUNT ON;

    SELECT u.UserID, u.UserName, u.FullName, u.EmailAddress, u.RoleID, r.RoleName
    FROM   SEC.Users u
    JOIN   SEC.Roles r ON u.RoleID = r.RoleID
    ORDER BY u.FullName;
END
GO
/****** Object:  StoredProcedure [SEC].[stpUsersU]    Script Date: 20/07/2026 9:29:42 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE   PROCEDURE [SEC].[stpUsersU]
(
    @UserID        SMALLINT,
    @UserName      NVARCHAR(100),
    @Password      NVARCHAR(256) = NULL,
    @FullName      NVARCHAR(100),
    @EmailAddress  NVARCHAR(255),
    @RoleID        TINYINT
)
AS
BEGIN
    SET NOCOUNT OFF;

    UPDATE SEC.Users
    SET    UserName     = @UserName,
           FullName     = @FullName,
           EmailAddress = @EmailAddress,
           RoleID       = @RoleID,
           UserPassword = CASE
                              WHEN @Password IS NOT NULL AND @Password <> ''
                              THEN HASHBYTES('SHA2_256', @Password)
                              ELSE UserPassword
                          END
    WHERE  UserID = @UserID;
END
GO
